    g->vertices = vertices;
    for (int i = 0; i < vertices; i++) {
        for (int j = 0; j < vertices; j++) {
            g->adjMatrix[i][j] = 0;
        }
    }
    return g;
}

void addEdge(Graph* g, int u, int v) {
    g->adjMatrix[u][v] = 1;
    g->adjMatrix[v][u] = 1;
}

void dfsUtil(Graph* g, int vertex, int* visited, int* result, int* index) {
    visited[vertex] = 1;
    result[(*index)++] = vertex;
    for (int i = 0; i < g->vertices; i++) {
        if (g->adjMatrix[vertex][i] == 1 && !visited[i]) {
            dfsUtil(g, i, visited, result, index);
        }
    }
}

int* dfs(Graph* g, int start, int* size) {
    int* visited = (int*)calloc(g->vertices, sizeof(int));
    int* result = (int*)malloc(g->vertices * sizeof(int));
    int index = 0;
    dfsUtil(g, start, visited, result, &index);
    *size = index;
    free(visited);
    return result;
}

int main() {
    Graph* g = createGraph(4);
    int edges[][2] = {{0, 1}, {1, 2}, {2, 3}};
    for (int i = 0; i < 3; i++) {
        addEdge(g, edges[i][0], edges[i][1]);
    }
    int size;
    int* result = dfs(g, 0, &size);
    printf("DFS traversal from vertex 0: [");
    for (int i = 0; i < size; i++) {
        printf("%d", result[i]);
        if (i < size - 1) printf(", ");
    }
    printf("]\n");
    free(result);
    free(g);
    return 0;
}
// Output: DFS traversal from vertex 0: [0, 1, 2, 3]

