#include <iostream>
#include <vector>

class Graph {
private:
    int vertices;
    std::vector<std::vector<int>> adjMatrix;

    void dfsUtil(int vertex, std::vector<bool>& visited, std::vector<int>& result) {
        visited[vertex] = true;
        result.push_back(vertex);
        for (int i = 0; i < vertices; i++) {
            if (adjMatrix[vertex][i] == 1 && !visited[i]) {
                dfsUtil(i, visited, result);
            }
        }
    }

public:
    Graph(int vertices) : vertices(vertices) {
        adjMatrix = std::vector<std::vector<int>>(vertices, std::vector<int>(vertices, 0));
    }

    void addEdge(int u, int v) {
        adjMatrix[u][v] = 1;
        adjMatrix[v][u] = 1;
    }

    std::vector<int> dfs(int start) {
        std::vector<bool> visited(vertices, false);
        std::vector<int> result;
        dfsUtil(start, visited, result);
        return result;
    }
};

int main() {
    Graph g(4);
    std::vector<std::pair<int, int>> edges = {{0, 1}, {1, 2}, {2, 3}};
    for (auto& edge : edges) {
        g.addEdge(edge.first, edge.second);
    }
    std::cout << "DFS traversal from vertex 0: [";
    auto result = g.dfs(0);
    for (size_t i = 0; i < result.size(); i++) {
        std::cout << result[i];
        if (i < result.size() - 1) std::cout << ", ";
    }
    std::cout << "]\n";
    return 0;
}
// Output: DFS traversal from vertex 0: [0, 1, 2, 3]
